const body = $json.body || {};
const items = [];

function pushItem(source, raw) {
  if (!raw) return;
  const comment_id = String(raw.comment_id || raw.id || raw.comment?.id || raw.parent_comment_id || '');
  const video_id = String(raw.video_id || raw.media_id || raw.post_id || raw.video?.id || '');
  const video_url = String(raw.video_url || raw.url || raw.permalink || '');
  const text = String(raw.text || raw.comment_text || raw.message || raw.comment?.text || '');
  const username = String(raw.username || raw.user_name || raw.user || raw.from?.username || raw.from?.name || '');
  const created_at = String(raw.created_at || raw.event_time || raw.create_time || new Date().toISOString());
  if (!comment_id || !text) return;
  items.push({
    source,
    comment_id,
    video_id,
    video_url,
    username,
    text,
    created_at,
    raw_value: raw
  });
}

if (Array.isArray(body.items)) {
  for (const raw of body.items) pushItem('items', raw);
} else if (Array.isArray(body.comment_queue)) {
  for (const raw of body.comment_queue) pushItem('comment_queue', raw);
} else if (Array.isArray(body.entry)) {
  for (const entry of body.entry) {
    for (const change of entry.changes || []) {
      const value = change.value || {};
      const from = value.from || value.sender || {};
      pushItem('webhook', {
        comment_id: value.comment_id || value.id || value.comment?.id || value.parent_id || '',
        video_id: value.video_id || value.media_id || value.post_id || value.video?.id || '',
        video_url: value.video_url || value.permalink || '',
        text: value.text || value.message || value.comment?.text || '',
        username: from.username || from.name || '',
        created_at: value.created_at || value.create_time || entry.time || new Date().toISOString(),
        raw_value: value
      });
    }
  }
} else if (body.comment_id || body.text) {
  pushItem('single', body);
}

function draftReply(text) {
  const raw = String(text || '').trim();
  const normalized = raw.toLowerCase();

  if (/^[\s🔥💯👏🙌⭐️✨]+$/.test(raw)) return raw.includes('🔥') ? 'Appreciate you 🔥' : 'Appreciate you 👏';
  if (/\b(agree|couldn.t agree|so true|truth|facts|fact)\b/i.test(normalized)) return 'Exactly. That is the part people usually learn under pressure.';
  if (/\b(attitude|ownership|care|cares|showing up|give a damn)\b/i.test(normalized)) return 'Exactly. Skill can be taught, ownership is different.';
  if (/\b(great|good|solid|love|video|take|advice|insight)\b/i.test(normalized)) return 'Appreciate that. I try to keep it practical.';
  if (/\b(experience|resume|skills?)\b/i.test(normalized)) return 'Experience matters, but I will take ownership over a perfect resume.';
  if (/\b(thanks|thank you)\b/i.test(normalized)) return 'Appreciate you.';
  return 'Appreciate you. That part matters more than people think.';
}

const holdPatterns = [
  /\b(sexy|hot|fine|date|single|marry|wife|husband|flirt|dm me)\b/i,
  /\b(race|racist|black|white|asian|mexican|arab|jew|muslim|christian)\b/i,
  /\b(trump|biden|republican|democrat|politics|election)\b/i,
  /\b(contract|lawsuit|sue|attorney|legal|payment|invoice|invest|investment)\b/i,
  /\b(fuck|shit|bitch|asshole|idiot|stupid)\b/i,
];

const replyMode = $env.TIKTOK_COMMENT_POST_URL ? 'connector' : 'approval';

return items.map((item) => {
  const normalized = item.text.toLowerCase();
  const risk = holdPatterns.some((pattern) => pattern.test(normalized)) ? 'hold_for_omar' : 'safe';
  return {
    json: {
      ...item,
      risk,
      reply_mode: replyMode,
      reply: risk === 'safe' ? draftReply(item.text) : '',
      status: risk === 'safe' ? 'drafted' : 'held'
    }
  };
});

